/* ─── HOOKS ─────────────────────────────────────────────────────── */
function useReveal(threshold = 0.12) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => { if (e.isIntersecting) setVisible(true); }, { threshold });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, []);
  return [ref, visible];
}

function useTypewriter(words, speed = 90) {
  const [text, setText] = useState("");
  const state = useRef({ wi: 0, ci: 0, deleting: false, waiting: false });
  useEffect(() => {
    let timeout;
    const tick = () => {
      const s = state.current;
      const word = words[s.wi];
      if (s.waiting) { s.waiting = false; s.deleting = true; timeout = setTimeout(tick, 80); return; }
      if (!s.deleting) {
        setText(word.slice(0, s.ci + 1));
        s.ci++;
        if (s.ci === word.length) { s.waiting = true; timeout = setTimeout(tick, 1800); return; }
      } else {
        setText(word.slice(0, s.ci - 1));
        s.ci--;
        if (s.ci === 0) { s.deleting = false; s.wi = (s.wi + 1) % words.length; }
      }
      timeout = setTimeout(tick, s.deleting ? 45 : speed);
    };
    timeout = setTimeout(tick, 800);
    return () => clearTimeout(timeout);
  }, []);
  return text;
}

