function Reveal({ children, delay = 0, y = 30 }) {
  const [ref, vis] = useReveal();
  return (
    <div ref={ref} style={{ opacity: vis?1:0, transform: vis?`translateY(0)`:`translateY(${y}px)`,
      transition:`opacity 0.75s ease ${delay}s, transform 0.75s ease ${delay}s` }}>
      {children}
    </div>
  );
}

/* ─── ANIMATED GLOBE (Canvas + HTML Overlays) ──────────────────── */
const ALL_TECH = [
  "React.js","Node.js","Python","C#","MySQL","MongoDB",
  "JavaScript","GPT-4","FastAPI","Git","Java","Express.js"
];

function TechGlobe() {
  const canvasRef = useRef(null);
  const containerRef = useRef(null);
  const [labelsData, setLabelsData] = useState([]);
  const animRef = useRef(null);
  
  // Interaction state
  const pointerRef = useRef({ isDown: false, x: 0, y: 0 });
  const rotationRef = useRef({ x: 0, y: 0, tx: 0, ty: 0 }); // current & target

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    const dpr = window.devicePixelRatio || 1;
    const size = 420; // Slightly larger for better visual breathing room
    canvas.width = size * dpr;
    canvas.height = size * dpr;
    canvas.style.width = size + "px";
    canvas.style.height = size + "px";
    ctx.scale(dpr, dpr);

    const cx = size / 2, cy = size / 2, R = 150;

    // Generate globe surface dots (Fibonacci sphere point cloud)
    const numDots = 800;
    const dots = [];
    const phi = Math.PI * (3 - Math.sqrt(5)); // Golden angle
    for (let i = 0; i < numDots; i++) {
      const y = 1 - (i / (numDots - 1)) * 2; // y goes from 1 to -1
      const radius = Math.sqrt(1 - y * y); // radius at y
      const theta = phi * i; // golden angle increment
      
      const x = Math.cos(theta) * radius;
      const z = Math.sin(theta) * radius;
      dots.push({ x: x * R, y: y * R, z: z * R });
    }

    // Tech label initial spherical coords
    const labelDefs = ALL_TECH.map((text, i) => {
      const lat = ((i % 4) / 3 - 0.5) * Math.PI * 0.7; // distribute vertically
      const lng = (i / ALL_TECH.length) * Math.PI * 2;
      const orbitR = R + 40; // float above globe
      return { 
        text, 
        baseX: Math.cos(lat) * Math.cos(lng) * orbitR,
        baseY: Math.sin(lat) * orbitR,
        baseZ: Math.cos(lat) * Math.sin(lng) * orbitR
      };
    });

    const draw = () => {
      ctx.clearRect(0, 0, size, size);

      // Smoothly interpolate rotation towards target
      rotationRef.current.x += (rotationRef.current.tx - rotationRef.current.x) * 0.05;
      rotationRef.current.y += (rotationRef.current.ty - rotationRef.current.y) * 0.05;
      
      // Auto-spin if not dragging
      if (!pointerRef.current.isDown) {
        rotationRef.current.tx -= 0.0035; 
      }

      const rotX = rotationRef.current.y; // Dragging Y changes X axis rotation
      const rotY = rotationRef.current.x; // Dragging X changes Y axis rotation

      const cosX = Math.cos(rotX), sinX = Math.sin(rotX);
      const cosY = Math.cos(rotY), sinY = Math.sin(rotY);

      // Utility to apply 3D rotation
      const rotate3D = (p) => {
        // Rotate around Y
        let x1 = p.x * cosY - p.z * sinY;
        let z1 = p.z * cosY + p.x * sinY;
        let y1 = p.y;
        // Rotate around X (tilt)
        let y2 = y1 * cosX - z1 * sinX;
        let z2 = z1 * cosX + y1 * sinX;
        return { ...p, x: x1, y: y2, z: z2 };
      };

      // Draw projected dots
      const projectedDots = dots.map(rotate3D);
      projectedDots.sort((a, b) => a.z - b.z); // Draw back to front

      projectedDots.forEach(p => {
        // Map depth to visual properties (fade out points far in the back)
        const depth = (p.z + R) / (R * 2); // 0 (back) to 1 (front)
        if (depth < 0.1) return; // Cull far back
        
        const alpha = 0.1 + (depth * 0.5); 
        const sz = 0.8 + (depth * 1.5);
        
        // Front dots are indigo-tinted, back dots are faded green-ish
        ctx.fillStyle = p.z > 0 
          ? `rgba(165,180,252,${alpha})` 
          : `rgba(52,211,153,${alpha * 0.4})`;
          
        ctx.beginPath();
        ctx.arc(cx + p.x, cy + p.y, sz, 0, Math.PI * 2);
        ctx.fill();
        
        // Occasional bright "stars" for glow effect on front dots
        if (p.z > R * 0.85 && Math.random() > 0.98) {
          ctx.beginPath();
          ctx.arc(cx + p.x, cy + p.y, sz * 2.5, 0, Math.PI * 2);
          ctx.fillStyle = "rgba(255,255,255,0.6)";
          ctx.fill();
        }
      });

      // Update HTML labels state
      const updatedLabels = labelDefs.map(def => {
        const p = rotate3D({ x: def.baseX, y: def.baseY, z: def.baseZ });
        // Calculate screen scale & opacity based on depth
        const depth = (p.z + R) / (R * 2); 
        const scale = 0.65 + depth * 0.5; // front gets bigger
        const opacity = depth > 0.4 ? 1 : Math.max(0, (depth - 0.2) * 4); // fade quickly in back
        
        return {
          text: def.text,
          x: cx + p.x,
          y: cy + p.y,
          z: p.z,
          scale,
          opacity,
          zIndex: Math.round(p.z + R) // sorting index
        };
      });
      setLabelsData(updatedLabels);

      animRef.current = requestAnimationFrame(draw);
    };
    
    draw();
    return () => cancelAnimationFrame(animRef.current);
  }, []);

  // Drag interaction handlers
  const handlePointerDown = (e) => {
    pointerRef.current.isDown = true;
    pointerRef.current.x = e.clientX || (e.touches && e.touches[0].clientX);
    pointerRef.current.y = e.clientY || (e.touches && e.touches[0].clientY);
  };
  
  const handlePointerMove = (e) => {
    if (!pointerRef.current.isDown) return;
    const nx = e.clientX || (e.touches && e.touches[0].clientX);
    const ny = e.clientY || (e.touches && e.touches[0].clientY);
    const dx = nx - pointerRef.current.x;
    const dy = ny - pointerRef.current.y;
    pointerRef.current.x = nx;
    pointerRef.current.y = ny;
    
    // Convert drag pixel distance to rotation angle
    rotationRef.current.tx += dx * 0.006;
    rotationRef.current.ty += dy * 0.006;
    
    // Clamp vertical rotation so you can't flip the globe completely upside down
    rotationRef.current.ty = Math.max(-1.2, Math.min(1.2, rotationRef.current.ty));
  };
  
  const handlePointerUp = () => { pointerRef.current.isDown = false; };

  return (
    <div ref={containerRef} 
      onPointerDown={handlePointerDown} onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp} onPointerLeave={handlePointerUp}
      style={{ position:"relative", width:420, height:420, cursor:'grab', userSelect:'none', touchAction:'none' }}>
      
      {/* Background Core Atmospheric Glow */}
      <div style={{ position:"absolute", top:"50%", left:"50%", transform:"translate(-50%,-50%)",
        width:280, height:280, borderRadius:"50%", 
        background:"radial-gradient(circle, rgba(99,102,241,0.18) 0%, rgba(52,211,153,0.05) 50%, transparent 70%)", 
        filter:"blur(32px)", pointerEvents:"none" }} />
      
      {/* WebGL-style Point Cloud Canvas */}
      <canvas ref={canvasRef} style={{ position:"absolute", top:0, left:0, zIndex:1 }} />
      
      {/* HTML Orbiting Labels (Glassmorphism overlays) */}
      {labelsData.map((lbl, i) => (
        <div key={i} style={{
          position:"absolute", top:0, left:0,
          transform: `translate3d(calc(${lbl.x}px - 50%), calc(${lbl.y}px - 50%), ${lbl.z}px) scale(${lbl.scale})`,
          opacity: lbl.opacity, zIndex: lbl.zIndex,
          pointerEvents: lbl.z > 0 ? 'auto' : 'none',
          transition: "opacity 0.1s linear, background 0.3s, border-color 0.3s",
          background: "rgba(15, 23, 42, 0.45)",
          border: `1px solid rgba(129,140,248,${lbl.opacity > 0.8 ? 0.25 : 0.05})`,
          backdropFilter: "blur(8px)", WebkitBackdropFilter: "blur(8px)",
          padding: "0.45rem 1rem", borderRadius: "100px",
          color: lbl.z > 0 ? "#f8fafc" : "#94a3b8",
          fontSize: "0.85rem", fontWeight: 500, fontFamily: "'Outfit', sans-serif",
          boxShadow: lbl.z > 0 ? "0 8px 24px rgba(0,0,0,0.3), inset 0 0 12px rgba(129,140,248,0.15)" : "none",
          whiteSpace: "nowrap"
        }}>
          {lbl.text}
        </div>
      ))}
    </div>
  );
}

